// FTP Client Connection and File Download
BEGIN
 // Establish control connection
 socket = connectToServer(serverIP, 21)

 // Read welcome message
 response = readResponse(socket)
 PRINT response

 // Send USER command
 sendCommand(socket, "USER anonymous")
 response = readResponse(socket)

 // Send PASS command
 sendCommand(socket, "PASS user@domain.com")
 response = readResponse(socket)

 IF response starts with "230" THEN
 PRINT "Login successful"

 // Set binary mode for file transfer
 sendCommand(socket, "TYPE I")
 readResponse(socket)

 // Enter passive mode
 sendCommand(socket, "PASV")
 response = readResponse(socket)
 // Parse IP and port from response
 dataIP = extractIP(response)
 dataPort = extractPort(response)

 // Connect for data transfer
 dataSocket = connectToServer(dataIP, dataPort)

 // Request file download
 sendCommand(socket, "RETR filename.txt")
 response = readResponse(socket)

 // Read file data
 fileData = receiveData(dataSocket)
 writeFile("local_filename.txt", fileData)

 // Close data connection
 close(dataSocket)

 // Quit FTP session
 sendCommand(socket, "QUIT")
 close(socket)
 ELSE
 PRINT "Login failed"
 ENDIF
END

// ACTIVE MODE CONNECTION ESTABLISHMENT
BEGIN
 // Client sends PORT command with chosen port
 clientPort = 50000 + random(1000)
 clientDataSocket = bindToPort(clientPort)

 sendCommand(controlSocket, "PORT " + clientIP + "," + highPort + "," + lowPort)
 response = readResponse(controlSocket) // Expect 200

 // Server initiates connection from port 20 to client
 serverDataSocket = acceptConnection(clientDataSocket)
 // Data transfer happens here
END

// PASSIVE MODE CONNECTION ESTABLISHMENT
BEGIN
 // Client sends PASV command
 sendCommand(controlSocket, "PASV")
 response = readResponse(controlSocket)
 // Response format: 227 Entering Passive Mode (h1,h2,h3,h4,p1,p2)
 // IP = h1.h2.h3.h4, Port = p1*256 + p2

 serverIP = extractIP(response)
 serverPort = extractPort(response)

 // Client initiates connection to server's data port
 dataSocket = connectToServer(serverIP, serverPort)
 // Data transfer happens here
END
